103	    public List<GameStat> fetchStatsForGame(int gameId, League league) {
104	        EspnBoxscoreResponse summary = fetchSummaryForGame(gameId, league);
105	        return summary != null ? toGameStats(summary, gameId) : new ArrayList<>();
106	    }
