108	    private EspnBoxscoreResponse fetchSummaryForGame(int gameId, League league) {
109	        String summaryUrl = String.format("%s/%s/%s/summary?event=%s",
110	                espnApiProperties.getBaseUrl(),
111	                league.getSport().getValue(),
112	                league.getValue(),
113	                gameId);
114	        try {
115	            return restTemplate.getForObject(summaryUrl, EspnBoxscoreResponse.class);
116	        } catch (Exception e) {
117	            logger.error(e.getMessage());
118	            return null;
119	        }
120	    }
