122	    private List<GameStat> toGameStats(EspnBoxscoreResponse summary, int gameId) {
123	        if (summary.getBoxscore() == null || summary.getBoxscore().getTeams() == null) {
124	            return new ArrayList<>();
125	        }
126	        return summary.getBoxscore().getTeams().stream()
127	                .flatMap(team -> espnBoxScoreMapper.toGameStat(team, gameId).stream())
