122	        try {
123	            if (!gameRepository.shouldUpdate()) {
124	                return;
125	            }
126	        } catch (Exception e) {
127	            logger.error(e.getMessage());
128	        }
129	        try {
130	            DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyyMMdd");
131	            String yesterday = LocalDate.now().minusDays(1).format(formatter);
132	            String today = LocalDate.now().format(formatter);
133	            int updatedGameCount = 0;
134	            for (League league : League.values()) {
135	                List<Game> games = espnService.fetchGames(league, yesterday, today, true);
136	                gameRepository.saveAll(games);
137	                updatedGameCount += games.size();
138	            }
139	            logger.info("Finished updating games for today, updated {} games in {}ms ",
140	                    updatedGameCount,
141	                    System.currentTimeMillis() - startTime);
