17	/**
18	 * Maps ESPN standings payloads into standings groups. ESPN's response shape
19	 * varies by endpoint (cdn.espn.com xhr payloads vs site.api.espn.com v2), so
20	 * this walks the JSON leniently rather than binding to typed POJOs. Port of
21	 * the frontend's standingsMapper.ts.
22	 */
23	@Component
24	public class EspnStandingsMapper {
25	
26	    private static final String FALLBACK_LOGO =
27	            "https://a.espncdn.com/i/teamlogos/leagues/500/nhl.png";
28	
29	    public List<StandingsGroupResponse> map(JsonNode payload) {
30	        List<StandingsGroupResponse> standings = new ArrayList<>();
31	        for (JsonNode group : getConferenceGroups(payload)) {
32	            StandingsGroupResponse parsed = parseConference(group);
33	            if (!parsed.getTeams().isEmpty()) {
34	                standings.add(parsed);
35	            }
36	        }
37	        return standings;
38	    }
39	
40	    private List<JsonNode> getConferenceGroups(JsonNode payload) {
41	        if (payload == null || payload.isMissingNode()) {
42	            return List.of();
43	        }
44	        JsonNode directGroups = payload.path("content").path("standings").path("groups");
45	        if (directGroups.isArray()) {
46	            return toList(directGroups);
47	        }
48	        JsonNode conferenceChildren = payload.path("children");
49	        if (conferenceChildren.isArray()) {
50	            List<JsonNode> conferences = toList(conferenceChildren).stream()
51	                    .filter(this::hasStandingsGroupShape)
52	                    .toList();
53	            if (!conferences.isEmpty()) {
54	                return conferences;
55	            }
56	        }
57	
58	        // Endpoint shapes vary; walk the payload and keep only groups that
59	        // contain standings entries directly or in nested groups.
60	        List<JsonNode> candidateGroups = new ArrayList<>();
61	        Set<JsonNode> visited = Collections.newSetFromMap(new IdentityHashMap<>());
62	        walk(payload, candidateGroups, visited);
63	        return candidateGroups;
64	    }
65	
66	    private void walk(JsonNode node, List<JsonNode> candidates, Set<JsonNode> visited) {
67	        if (node == null || !node.isContainer() || visited.contains(node)) {
68	            return;
69	        }
70	        visited.add(node);
71	
72	        for (String field : new String[]{"groups", "children", "items"}) {
73	            JsonNode collection = node.path(field);
74	            if (!collection.isArray()) {
75	                continue;
76	            }
77	            for (JsonNode group : collection) {
78	                if (hasStandingsGroupShape(group)) {
79	                    candidates.add(group);
80	                }

